import{_ as a,c as t,b as i,o}from"./app-RrIk7Rat.js";const n={};function s(l,e){return o(),t("div",null,e[0]||(e[0]=[i('<h1 id="imageselection-modal" tabindex="-1"><a class="header-anchor" href="#imageselection-modal"><span>ImageSelection Modal</span></a></h1><p>Displays a modal dialog for selecting or entering an image manifest URL.</p><hr><h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview"><span>Overview</span></a></h2><p>The <code>ImageSelectionModal</code> component:</p><ul><li>Shows a modal dialog (currently a placeholder) for the user to input or select a manifest URL.</li><li>Uses the Vuex store to control modal visibility and manage the manifest URL.</li><li>On confirmation, triggers actions to load the manifest.</li></ul><hr><h2 id="layout" tabindex="-1"><a class="header-anchor" href="#layout"><span>Layout</span></a></h2><ul><li><strong>Modal</strong>: (Currently a placeholder <code>&lt;div v-if=&quot;visible&quot;&gt;Hello&lt;/div&gt;</code>)</li><li><strong>(Commented)</strong>: Modal with header, body, input for URL, and confirmation button.</li></ul><hr><h2 id="props" tabindex="-1"><a class="header-anchor" href="#props"><span>Props</span></a></h2><p><em>None</em></p><hr><h2 id="computed-properties" tabindex="-1"><a class="header-anchor" href="#computed-properties"><span>Computed Properties</span></a></h2><table><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>visible</td><td>Modal visibility, synced with Vuex store</td></tr><tr><td>url</td><td>Manifest URL, synced with Vuex store</td></tr></tbody></table><hr><h2 id="methods" tabindex="-1"><a class="header-anchor" href="#methods"><span>Methods</span></a></h2><table><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>openManifest</td><td>Hides the modal and dispatches actions to load the manifest</td></tr></tbody></table><hr><h2 id="example" tabindex="-1"><a class="header-anchor" href="#example"><span>Example</span></a></h2><div class="language-vue line-numbers-mode" data-highlighter="prismjs" data-ext="vue"><pre><code><span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>ImageSelectionModal</span> <span class="token punctuation">/&gt;</span></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div>',21)]))}const d=a(n,[["render",s]]),c=JSON.parse('{"path":"/technical/ImageSelectionModal.html","title":"ImageSelection Modal","lang":"en-US","frontmatter":{},"git":{"updatedTime":1756211745000,"contributors":[{"name":"Hizkiel","username":"Hizkiel","email":"hizclick@gmail.com","commits":2,"url":"https://github.com/Hizkiel"}],"changelog":[{"hash":"f154f171982bcbf31ca935ebf59603fd9f7ba544","time":1756211745000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Remove user documentation directory"},{"hash":"addcf634062a696867cd389eb76f27f467f4a69a","time":1747234892000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Correcting the impits based on the pr comments"}]},"filePathRelative":"technical/ImageSelectionModal.md"}');export{d as comp,c as data};
